    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "- Item 1")
    assert String.contains?(content, "- Item 2")
    assert String.contains?(content, "- Item 3")
  end
end
